import { Resource } from './base.js';
import { Paginated } from '../pagination.js';
import type { PaginationParams, PaginatedResponse, DeleteResult } from '../types/common.js';
import type {
  Webhook,
  WebhookWithSecret,
  CreateWebhookInput,
} from '../types/webhooks.js';
import type { PaginatedPromise } from '../pagination.js';

export class WebhooksResource extends Resource {
  /**
   * List registered webhooks.
   * GET /webhooks
   */
  list(params?: PaginationParams): PaginatedPromise<Webhook> {
    const initialPromise = this.transport
      .request<PaginatedResponse<Webhook>>('GET', '/webhooks', {
        query: params as Record<string, string | number | boolean | undefined>,
      })
      .then((r) => r.data);

    const fetchPage = (cursor: string) =>
      this.transport
        .request<PaginatedResponse<Webhook>>('GET', '/webhooks', {
          query: { ...params, cursor } as Record<string, string | number | boolean | undefined>,
        })
        .then((r) => r.data);

    return Paginated.from(initialPromise, fetchPage);
  }

  /**
   * Register a new webhook endpoint.
   * POST /webhooks
   */
  async create(input: CreateWebhookInput): Promise<WebhookWithSecret> {
    const response = await this.transport.request<WebhookWithSecret>(
      'POST',
      '/webhooks',
      { body: input },
    );
    return response.data;
  }

  /**
   * Delete a webhook endpoint.
   * DELETE /webhooks/:id
   */
  async del(id: string): Promise<DeleteResult> {
    const response = await this.transport.request<DeleteResult>('DELETE', `/webhooks/${id}`);
    return response.data;
  }
}
