import type { WebhookEvent } from './types/webhooks.js';
import { RentaError } from './errors.js';

/**
 * Parse a Renta-Signature header into its components.
 * Format: t=<unix_timestamp>,v1=<hex_hmac_sha256>
 */
function parseSignature(signature: string): { timestamp: string; hmac: string } {
  const parts = Object.fromEntries(
    signature.split(',').map((part) => {
      const [key, ...rest] = part.split('=');
      return [key, rest.join('=')];
    }),
  );

  const timestamp = parts['t'];
  const hmac = parts['v1'];

  if (!timestamp || !hmac) {
    throw new RentaError(
      400,
      {
        error: {
          code: 'webhook_signature_invalid',
          message: 'Invalid signature format',
        },
      },
      '',
    );
  }

  return { timestamp, hmac };
}

/**
 * Constant-time string comparison.
 * Uses crypto.timingSafeEqual in Node.js, manual XOR comparison in browsers.
 */
async function timingSafeEqual(a: string, b: string): Promise<boolean> {
  if (a.length !== b.length) return false;

  // Node.js: use crypto.timingSafeEqual
  try {
    const crypto = await import('node:crypto');
    if (crypto.timingSafeEqual) {
      return crypto.timingSafeEqual(Buffer.from(a), Buffer.from(b));
    }
  } catch {
    // Not in Node.js — fall through to browser implementation
  }

  // Browser fallback: manual constant-time comparison
  let result = 0;
  for (let i = 0; i < a.length; i++) {
    result |= a.charCodeAt(i) ^ b.charCodeAt(i);
  }
  return result === 0;
}

/**
 * Compute HMAC-SHA256 and return hex string.
 * Uses Node.js crypto module when available, falls back to Web Crypto API.
 */
async function hmacSha256Hex(secret: string, payload: string): Promise<string> {
  // Node.js
  try {
    const crypto = await import('node:crypto');
    if (crypto.createHmac) {
      return crypto.createHmac('sha256', secret).update(payload).digest('hex');
    }
  } catch {
    // Not in Node.js — fall through to browser implementation
  }

  // Browser / Edge runtime: Web Crypto API
  const encoder = new TextEncoder();
  const keyData = encoder.encode(secret);
  const msgData = encoder.encode(payload);

  const cryptoKey = await globalThis.crypto.subtle.importKey(
    'raw',
    keyData,
    { name: 'HMAC', hash: 'SHA-256' },
    false,
    ['sign'],
  );

  const signature = await globalThis.crypto.subtle.sign('HMAC', cryptoKey, msgData);
  const hashArray = new Uint8Array(signature);
  return Array.from(hashArray)
    .map((b) => b.toString(16).padStart(2, '0'))
    .join('');
}

/**
 * Webhook verification utilities.
 * Verify incoming webhook signatures from the Renta API.
 */
export const webhookVerifier = {
  /**
   * Verify a webhook signature and return the parsed event.
   *
   * @param rawBody - The raw request body as a string or Buffer
   * @param signature - The Renta-Signature header value
   * @param secret - The webhook signing secret
   * @returns The parsed WebhookEvent
   * @throws RentaError if verification fails
   */
  async verify(
    rawBody: string | Buffer,
    signature: string,
    secret: string,
  ): Promise<WebhookEvent> {
    // 1. Parse the signature header
    const { timestamp, hmac: expectedSig } = parseSignature(signature);

    // 2. Timestamp validation — reject events older than 5 minutes
    const timestampAge = Math.floor(Date.now() / 1000) - parseInt(timestamp, 10);
    if (timestampAge > 300) {
      throw new RentaError(
        400,
        {
          error: {
            code: 'webhook_timestamp_expired',
            message: 'Webhook timestamp too old (>5 minutes)',
          },
        },
        '',
      );
    }

    // 3. Compute expected HMAC
    const bodyStr = typeof rawBody === 'string' ? rawBody : rawBody.toString('utf-8');
    const signedPayload = `${timestamp}.${bodyStr}`;
    const computedSig = await hmacSha256Hex(secret, signedPayload);

    // 4. Constant-time comparison
    const isValid = await timingSafeEqual(computedSig, expectedSig);
    if (!isValid) {
      throw new RentaError(
        400,
        {
          error: {
            code: 'webhook_signature_invalid',
            message: 'Signature verification failed',
          },
        },
        '',
      );
    }

    // 5. Parse and return the event
    const event: WebhookEvent = JSON.parse(bodyStr);
    return event;
  },
};
