import { Resource } from './base.js';
import { Paginated } from '../pagination.js';
import type { PaginatedResponse } from '../types/common.js';
import type {
  Customer,
  CustomerListParams,
  CreateCustomerInput,
  UpdateCustomerInput,
} from '../types/customers.js';
import type { PaginatedPromise } from '../pagination.js';

export class CustomersResource extends Resource {
  /**
   * List customers with optional search and tag filters.
   * GET /customers
   */
  list(params?: CustomerListParams): PaginatedPromise<Customer> {
    const initialPromise = this.transport
      .request<PaginatedResponse<Customer>>('GET', '/customers', {
        query: params as Record<string, string | number | boolean | undefined>,
      })
      .then((r) => r.data);

    const fetchPage = (cursor: string) =>
      this.transport
        .request<PaginatedResponse<Customer>>('GET', '/customers', {
          query: { ...params, cursor } as Record<string, string | number | boolean | undefined>,
        })
        .then((r) => r.data);

    return Paginated.from(initialPromise, fetchPage);
  }

  /**
   * Get a single customer by ID.
   * GET /customers/:id
   */
  async get(id: string): Promise<Customer> {
    const response = await this.transport.request<Customer>('GET', `/customers/${id}`);
    return response.data;
  }

  /**
   * Create a new customer.
   * POST /customers
   */
  async create(input: CreateCustomerInput): Promise<Customer> {
    const response = await this.transport.request<Customer>('POST', '/customers', {
      body: input,
    });
    return response.data;
  }

  /**
   * Update a customer (partial update).
   * PATCH /customers/:id
   */
  async update(id: string, input: UpdateCustomerInput): Promise<Customer> {
    const response = await this.transport.request<Customer>('PATCH', `/customers/${id}`, {
      body: input,
    });
    return response.data;
  }
}
