import { Resource } from './base.js';
import type {
  CalculatePricingInput,
  PricingBreakdown,
} from '../types/common.js';

export class PricingResource extends Resource {
  /**
   * Calculate full pricing breakdown without creating a booking.
   * POST /pricing/calculate
   */
  async calculate(input: CalculatePricingInput): Promise<PricingBreakdown> {
    const response = await this.transport.request<PricingBreakdown>(
      'POST',
      '/pricing/calculate',
      { body: input },
    );
    return response.data;
  }
}
