import { Resource } from './base.js';
import type {
  DepositHoldInput,
  DepositHold,
  DepositCaptureInput,
  DepositReleaseInput,
  DepositResult,
} from '../types/payments.js';

export class DepositsResource extends Resource {
  /**
   * Place an authorization hold on a customer's card.
   * POST /deposits/hold
   */
  async hold(input: DepositHoldInput): Promise<DepositHold> {
    const response = await this.transport.request<DepositHold>(
      'POST',
      '/deposits/hold',
      { body: input },
    );
    return response.data;
  }

  /**
   * Capture all or part of a held deposit.
   * POST /deposits/capture
   */
  async capture(input: DepositCaptureInput): Promise<DepositResult> {
    const response = await this.transport.request<DepositResult>(
      'POST',
      '/deposits/capture',
      { body: input },
    );
    return response.data;
  }

  /**
   * Release a held deposit back to the customer.
   * POST /deposits/release
   */
  async release(input: DepositReleaseInput): Promise<DepositResult> {
    const response = await this.transport.request<DepositResult>(
      'POST',
      '/deposits/release',
      { body: input },
    );
    return response.data;
  }
}
