/** Shape of the error response from the Renta API. */
export interface ApiErrorBody {
  error: {
    code: string;
    message: string;
    details?: {
      errors?: ValidationFieldError[];
      [key: string]: unknown;
    };
  };
}

export interface ValidationFieldError {
  field: string;
  message: string;
}

/**
 * Base error for all Renta API errors.
 */
export class RentaError extends Error {
  /** HTTP status code from the API response. */
  readonly statusCode: number;

  /** Machine-readable error code from the API. */
  readonly code: string;

  /** X-Request-Id from the API response (for support). */
  readonly requestId: string;

  /** Additional error details from the API response. */
  readonly details?: Record<string, unknown>;

  constructor(statusCode: number, body: ApiErrorBody, requestId: string) {
    super(body.error.message);
    this.name = 'RentaError';
    this.statusCode = statusCode;
    this.code = body.error.code;
    this.requestId = requestId;
    this.details = body.error.details;
  }
}

/**
 * Thrown on 401 (unauthorized) or 403 (forbidden).
 */
export class RentaAuthError extends RentaError {
  constructor(statusCode: number, body: ApiErrorBody, requestId: string) {
    super(statusCode, body, requestId);
    this.name = 'RentaAuthError';
  }
}

/**
 * Thrown on 404 (not found).
 */
export class RentaNotFoundError extends RentaError {
  constructor(body: ApiErrorBody, requestId: string) {
    super(404, body, requestId);
    this.name = 'RentaNotFoundError';
  }
}

/**
 * Thrown on 400 (bad request) or 422 (unprocessable entity).
 */
export class RentaValidationError extends RentaError {
  /** Array of field-level validation errors. */
  readonly errors: ValidationFieldError[];

  constructor(statusCode: number, body: ApiErrorBody, requestId: string) {
    super(statusCode, body, requestId);
    this.name = 'RentaValidationError';
    this.errors = body.error.details?.errors ?? [];
  }
}

/**
 * Thrown on 409 (conflict).
 */
export class RentaConflictError extends RentaError {
  constructor(body: ApiErrorBody, requestId: string) {
    super(409, body, requestId);
    this.name = 'RentaConflictError';
  }
}

/**
 * Thrown on 429 (rate limited).
 */
export class RentaRateLimitError extends RentaError {
  /** Seconds to wait before retrying. */
  readonly retryAfter: number;

  constructor(body: ApiErrorBody, requestId: string, retryAfter: number) {
    super(429, body, requestId);
    this.name = 'RentaRateLimitError';
    this.retryAfter = retryAfter;
  }
}

/**
 * Thrown on 500+ (server error).
 */
export class RentaInternalError extends RentaError {
  constructor(statusCode: number, body: ApiErrorBody, requestId: string) {
    super(statusCode, body, requestId);
    this.name = 'RentaInternalError';
  }
}

/**
 * Map an HTTP status code to the appropriate error class and throw.
 */
export function throwApiError(
  status: number,
  body: ApiErrorBody,
  requestId: string,
  retryAfter?: number,
): never {
  switch (status) {
    case 401:
    case 403:
      throw new RentaAuthError(status, body, requestId);
    case 404:
      throw new RentaNotFoundError(body, requestId);
    case 400:
    case 422:
      throw new RentaValidationError(status, body, requestId);
    case 409:
      throw new RentaConflictError(body, requestId);
    case 429:
      throw new RentaRateLimitError(body, requestId, retryAfter ?? 0);
    default:
      if (status >= 500) {
        throw new RentaInternalError(status, body, requestId);
      }
      throw new RentaError(status, body, requestId);
  }
}
