import { Resource } from './base.js';
import { Paginated } from '../pagination.js';
import type { PaginatedResponse } from '../types/common.js';
import type {
  WaiverTemplate,
  WaiverTemplateListParams,
  SignWaiverInput,
  WaiverSignResult,
  WaiverStatus,
} from '../types/waivers.js';
import type { PaginatedPromise } from '../pagination.js';

export class WaiversResource extends Resource {
  /**
   * List active waiver templates.
   * GET /waivers/templates
   */
  templates(params?: WaiverTemplateListParams): PaginatedPromise<WaiverTemplate> {
    const initialPromise = this.transport
      .request<PaginatedResponse<WaiverTemplate>>('GET', '/waivers/templates', {
        query: params as Record<string, string | number | boolean | undefined>,
      })
      .then((r) => r.data);

    const fetchPage = (cursor: string) =>
      this.transport
        .request<PaginatedResponse<WaiverTemplate>>('GET', '/waivers/templates', {
          query: { ...params, cursor } as Record<string, string | number | boolean | undefined>,
        })
        .then((r) => r.data);

    return Paginated.from(initialPromise, fetchPage);
  }

  /**
   * Sign a waiver for a booking.
   * POST /waivers/sign
   */
  async sign(input: SignWaiverInput): Promise<WaiverSignResult> {
    const response = await this.transport.request<WaiverSignResult>(
      'POST',
      '/waivers/sign',
      { body: input },
    );
    return response.data;
  }

  /**
   * Get waiver signing status for a booking.
   * GET /waivers/status/:bookingId
   */
  async status(bookingId: string): Promise<WaiverStatus> {
    const response = await this.transport.request<WaiverStatus>(
      'GET',
      `/waivers/status/${bookingId}`,
    );
    return response.data;
  }
}
