import { Resource } from './base.js';
import { Paginated } from '../pagination.js';
import type { PaginatedResponse, DeleteResult } from '../types/common.js';
import type {
  FleetCategory,
  FleetCategoryListParams,
  CreateFleetCategoryInput,
  UpdateFleetCategoryInput,
  FleetItem,
  FleetItemListParams,
  CreateFleetItemInput,
  UpdateFleetItemInput,
} from '../types/fleet.js';
import type { PaginatedPromise } from '../pagination.js';

export class FleetCategoriesResource extends Resource {
  /**
   * List fleet categories.
   * GET /fleet/categories
   */
  list(params?: FleetCategoryListParams): PaginatedPromise<FleetCategory> {
    const initialPromise = this.transport
      .request<PaginatedResponse<FleetCategory>>('GET', '/fleet/categories', {
        query: params as Record<string, string | number | boolean | undefined>,
      })
      .then((r) => r.data);

    const fetchPage = (cursor: string) =>
      this.transport
        .request<PaginatedResponse<FleetCategory>>('GET', '/fleet/categories', {
          query: { ...params, cursor } as Record<string, string | number | boolean | undefined>,
        })
        .then((r) => r.data);

    return Paginated.from(initialPromise, fetchPage);
  }

  /**
   * Get a single fleet category by ID.
   * GET /fleet/categories/:id
   */
  async get(id: string): Promise<FleetCategory> {
    const response = await this.transport.request<FleetCategory>(
      'GET',
      `/fleet/categories/${id}`,
    );
    return response.data;
  }

  /**
   * Create a new fleet category.
   * POST /fleet/categories
   */
  async create(input: CreateFleetCategoryInput): Promise<FleetCategory> {
    const response = await this.transport.request<FleetCategory>(
      'POST',
      '/fleet/categories',
      { body: input },
    );
    return response.data;
  }

  /**
   * Update a fleet category.
   * PATCH /fleet/categories/:id
   */
  async update(id: string, input: UpdateFleetCategoryInput): Promise<FleetCategory> {
    const response = await this.transport.request<FleetCategory>(
      'PATCH',
      `/fleet/categories/${id}`,
      { body: input },
    );
    return response.data;
  }

  /**
   * Delete a fleet category.
   * DELETE /fleet/categories/:id
   */
  async del(id: string): Promise<DeleteResult> {
    const response = await this.transport.request<DeleteResult>(
      'DELETE',
      `/fleet/categories/${id}`,
    );
    return response.data;
  }
}

export class FleetItemsResource extends Resource {
  /**
   * List fleet items with optional filters.
   * GET /fleet/items
   */
  list(params?: FleetItemListParams): PaginatedPromise<FleetItem> {
    const initialPromise = this.transport
      .request<PaginatedResponse<FleetItem>>('GET', '/fleet/items', {
        query: params as Record<string, string | number | boolean | undefined>,
      })
      .then((r) => r.data);

    const fetchPage = (cursor: string) =>
      this.transport
        .request<PaginatedResponse<FleetItem>>('GET', '/fleet/items', {
          query: { ...params, cursor } as Record<string, string | number | boolean | undefined>,
        })
        .then((r) => r.data);

    return Paginated.from(initialPromise, fetchPage);
  }

  /**
   * Get a single fleet item by ID.
   * GET /fleet/items/:id
   */
  async get(id: string): Promise<FleetItem> {
    const response = await this.transport.request<FleetItem>(
      'GET',
      `/fleet/items/${id}`,
    );
    return response.data;
  }

  /**
   * Create a new fleet item.
   * POST /fleet/items
   */
  async create(input: CreateFleetItemInput): Promise<FleetItem> {
    const response = await this.transport.request<FleetItem>(
      'POST',
      '/fleet/items',
      { body: input },
    );
    return response.data;
  }

  /**
   * Update a fleet item (partial update).
   * PATCH /fleet/items/:id
   */
  async update(id: string, input: UpdateFleetItemInput): Promise<FleetItem> {
    const response = await this.transport.request<FleetItem>(
      'PATCH',
      `/fleet/items/${id}`,
      { body: input },
    );
    return response.data;
  }

  /**
   * Delete (soft-delete) a fleet item.
   * DELETE /fleet/items/:id
   */
  async del(id: string): Promise<DeleteResult> {
    const response = await this.transport.request<DeleteResult>(
      'DELETE',
      `/fleet/items/${id}`,
    );
    return response.data;
  }
}
