import { Resource } from './base.js';
import { Paginated } from '../pagination.js';
import type { PaginatedResponse, DeleteResult } from '../types/common.js';
import type {
  Coupon,
  CouponListParams,
  CreateCouponInput,
  UpdateCouponInput,
  ValidateCouponInput,
  CouponValidation,
} from '../types/coupons.js';
import type { PaginatedPromise } from '../pagination.js';

export class CouponsResource extends Resource {
  /**
   * List coupons with optional active filter.
   * GET /coupons
   */
  list(params?: CouponListParams): PaginatedPromise<Coupon> {
    const initialPromise = this.transport
      .request<PaginatedResponse<Coupon>>('GET', '/coupons', {
        query: params as Record<string, string | number | boolean | undefined>,
      })
      .then((r) => r.data);

    const fetchPage = (cursor: string) =>
      this.transport
        .request<PaginatedResponse<Coupon>>('GET', '/coupons', {
          query: { ...params, cursor } as Record<string, string | number | boolean | undefined>,
        })
        .then((r) => r.data);

    return Paginated.from(initialPromise, fetchPage);
  }

  /**
   * Get a single coupon by ID.
   * GET /coupons/:id
   */
  async get(id: string): Promise<Coupon> {
    const response = await this.transport.request<Coupon>('GET', `/coupons/${id}`);
    return response.data;
  }

  /**
   * Create a new coupon.
   * POST /coupons
   */
  async create(input: CreateCouponInput): Promise<Coupon> {
    const response = await this.transport.request<Coupon>('POST', '/coupons', {
      body: input,
    });
    return response.data;
  }

  /**
   * Update a coupon (partial update).
   * PATCH /coupons/:id
   */
  async update(id: string, input: UpdateCouponInput): Promise<Coupon> {
    const response = await this.transport.request<Coupon>('PATCH', `/coupons/${id}`, {
      body: input,
    });
    return response.data;
  }

  /**
   * Delete a coupon.
   * DELETE /coupons/:id
   */
  async del(id: string): Promise<DeleteResult> {
    const response = await this.transport.request<DeleteResult>('DELETE', `/coupons/${id}`);
    return response.data;
  }

  /**
   * Validate a coupon code without applying it.
   * POST /coupons/validate
   */
  async validate(input: ValidateCouponInput): Promise<CouponValidation> {
    const response = await this.transport.request<CouponValidation>(
      'POST',
      '/coupons/validate',
      { body: input },
    );
    return response.data;
  }
}
