import type { RentaConfig } from './types/config.js';
import { Transport } from './transport.js';
import { FleetCategoriesResource, FleetItemsResource } from './resources/fleet.js';
import { BookingsResource } from './resources/bookings.js';
import { CustomersResource } from './resources/customers.js';
import { AddonsResource } from './resources/addons.js';
import { CouponsResource } from './resources/coupons.js';
import { WaiversResource } from './resources/waivers.js';
import { PaymentsResource } from './resources/payments.js';
import { DepositsResource } from './resources/deposits.js';
import { AvailabilityResource } from './resources/availability.js';
import { PricingResource } from './resources/pricing.js';
import { WebhooksResource } from './resources/webhooks-resource.js';
import { webhookVerifier } from './webhooks.js';

export class Renta {
  /** Static webhook verification utility. */
  static webhooks = webhookVerifier;

  readonly fleet: {
    readonly categories: FleetCategoriesResource;
    readonly items: FleetItemsResource;
  };
  readonly bookings: BookingsResource;
  readonly customers: CustomersResource;
  readonly addons: AddonsResource;
  readonly coupons: CouponsResource;
  readonly waivers: WaiversResource;
  readonly payments: PaymentsResource;
  readonly deposits: DepositsResource;
  readonly availability: AvailabilityResource;
  readonly pricing: PricingResource;
  readonly webhooks: WebhooksResource;

  constructor(config: RentaConfig) {
    const transport = new Transport(config);

    this.fleet = {
      categories: new FleetCategoriesResource(transport),
      items: new FleetItemsResource(transport),
    };
    this.bookings = new BookingsResource(transport);
    this.customers = new CustomersResource(transport);
    this.addons = new AddonsResource(transport);
    this.coupons = new CouponsResource(transport);
    this.waivers = new WaiversResource(transport);
    this.payments = new PaymentsResource(transport);
    this.deposits = new DepositsResource(transport);
    this.availability = new AvailabilityResource(transport);
    this.pricing = new PricingResource(transport);
    this.webhooks = new WebhooksResource(transport);
  }
}
