import { Resource } from './base.js';
import { Paginated } from '../pagination.js';
import type { PaginatedResponse, DeleteResult } from '../types/common.js';
import type {
  Addon,
  AddonListParams,
  CreateAddonInput,
  UpdateAddonInput,
} from '../types/addons.js';
import type { PaginatedPromise } from '../pagination.js';

export class AddonsResource extends Resource {
  /**
   * List add-ons.
   * GET /addons
   */
  list(params?: AddonListParams): PaginatedPromise<Addon> {
    const initialPromise = this.transport
      .request<PaginatedResponse<Addon>>('GET', '/addons', {
        query: params as Record<string, string | number | boolean | undefined>,
      })
      .then((r) => r.data);

    const fetchPage = (cursor: string) =>
      this.transport
        .request<PaginatedResponse<Addon>>('GET', '/addons', {
          query: { ...params, cursor } as Record<string, string | number | boolean | undefined>,
        })
        .then((r) => r.data);

    return Paginated.from(initialPromise, fetchPage);
  }

  /**
   * Get a single add-on by ID.
   * GET /addons/:id
   */
  async get(id: string): Promise<Addon> {
    const response = await this.transport.request<Addon>('GET', `/addons/${id}`);
    return response.data;
  }

  /**
   * Create a new add-on.
   * POST /addons
   */
  async create(input: CreateAddonInput): Promise<Addon> {
    const response = await this.transport.request<Addon>('POST', '/addons', {
      body: input,
    });
    return response.data;
  }

  /**
   * Update an add-on (partial update).
   * PATCH /addons/:id
   */
  async update(id: string, input: UpdateAddonInput): Promise<Addon> {
    const response = await this.transport.request<Addon>('PATCH', `/addons/${id}`, {
      body: input,
    });
    return response.data;
  }

  /**
   * Delete an add-on.
   * DELETE /addons/:id
   */
  async del(id: string): Promise<DeleteResult> {
    const response = await this.transport.request<DeleteResult>('DELETE', `/addons/${id}`);
    return response.data;
  }
}
