import type { PaginatedResponse } from './types/common.js';

/**
 * Paginated result that is both PromiseLike and AsyncIterable.
 *
 * - `await list()` → resolves to a Paginated<T> with .data, .hasMore, .nextCursor
 * - `for await (const item of list())` → iterates all items across all pages
 * - `await list().toArray()` → collects all items into an array
 */
export class Paginated<T> implements AsyncIterable<T> {
  /** Items in the current page. */
  readonly data: T[];

  /** Whether more pages exist. */
  readonly hasMore: boolean;

  /** Cursor to fetch the next page (null if no more pages). */
  readonly nextCursor: string | null;

  private readonly fetchPage: (cursor: string) => Promise<PaginatedResponse<T>>;

  constructor(
    response: PaginatedResponse<T>,
    fetchPage: (cursor: string) => Promise<PaginatedResponse<T>>,
  ) {
    this.data = response.data;
    this.hasMore = response.has_more;
    this.nextCursor = response.next_cursor;
    this.fetchPage = fetchPage;
  }

  /**
   * Async iterator that automatically fetches subsequent pages.
   * Yields individual items, not pages.
   */
  async *[Symbol.asyncIterator](): AsyncIterator<T> {
    let page: PaginatedResponse<T> = {
      data: this.data,
      has_more: this.hasMore,
      next_cursor: this.nextCursor,
    };

    while (true) {
      for (const item of page.data) {
        yield item;
      }
      if (!page.has_more || !page.next_cursor) break;
      page = await this.fetchPage(page.next_cursor);
    }
  }

  /**
   * Collect ALL items across all pages into a single array.
   * ⚠️ Use with caution on large datasets.
   */
  async toArray(): Promise<T[]> {
    const items: T[] = [];
    for await (const item of this) {
      items.push(item);
    }
    return items;
  }

  /**
   * Fetch the next page. Returns null if no more pages.
   */
  async nextPage(): Promise<Paginated<T> | null> {
    if (!this.hasMore || !this.nextCursor) return null;
    const response = await this.fetchPage(this.nextCursor);
    return new Paginated(response, this.fetchPage);
  }

  /**
   * Create a Paginated<T> from a promise that resolves to the first page.
   * Returns a PaginatedPromise that is both PromiseLike<Paginated<T>> and AsyncIterable<T>.
   */
  static from<T>(
    initialPromise: Promise<PaginatedResponse<T>>,
    fetchPage: (cursor: string) => Promise<PaginatedResponse<T>>,
  ): PaginatedPromise<T> {
    return new PaginatedPromise(initialPromise, fetchPage);
  }
}

/**
 * A lazy wrapper that is both PromiseLike<Paginated<T>> and AsyncIterable<T>.
 * The initial fetch only happens when awaited or iterated.
 */
export class PaginatedPromise<T> implements PromiseLike<Paginated<T>>, AsyncIterable<T> {
  private readonly _initialPromise: Promise<PaginatedResponse<T>>;
  private readonly _fetchPage: (cursor: string) => Promise<PaginatedResponse<T>>;
  private _resolved: Paginated<T> | null = null;

  constructor(
    initialPromise: Promise<PaginatedResponse<T>>,
    fetchPage: (cursor: string) => Promise<PaginatedResponse<T>>,
  ) {
    this._initialPromise = initialPromise;
    this._fetchPage = fetchPage;
  }

  private async _resolve(): Promise<Paginated<T>> {
    if (!this._resolved) {
      const response = await this._initialPromise;
      this._resolved = new Paginated(response, this._fetchPage);
    }
    return this._resolved;
  }

  then<TResult1 = Paginated<T>, TResult2 = never>(
    onfulfilled?: ((value: Paginated<T>) => TResult1 | PromiseLike<TResult1>) | null,
    onrejected?: ((reason: unknown) => TResult2 | PromiseLike<TResult2>) | null,
  ): Promise<TResult1 | TResult2> {
    return this._resolve().then(onfulfilled, onrejected);
  }

  async *[Symbol.asyncIterator](): AsyncIterator<T> {
    const paginated = await this._resolve();
    yield* paginated;
  }

  /**
   * Collect ALL items across all pages into a single array.
   */
  async toArray(): Promise<T[]> {
    const paginated = await this._resolve();
    return paginated.toArray();
  }
}
