import { Resource } from './base.js';
import type {
  CheckAvailabilityInput,
  AvailabilityResult,
} from '../types/common.js';

export class AvailabilityResource extends Resource {
  /**
   * Check fleet item availability for a date range.
   * POST /availability/check
   */
  async check(input: CheckAvailabilityInput): Promise<AvailabilityResult> {
    const response = await this.transport.request<AvailabilityResult>(
      'POST',
      '/availability/check',
      { body: input },
    );
    return response.data;
  }
}
