import { Resource } from './base.js';
import { Paginated } from '../pagination.js';
import type { PaginatedResponse } from '../types/common.js';
import type {
  Booking,
  BookingListParams,
  CreateBookingInput,
  UpdateBookingInput,
  CancelBookingInput,
  ExtendBookingInput,
  SwapItemInput,
} from '../types/bookings.js';
import type { PaginatedPromise } from '../pagination.js';

export class BookingsResource extends Resource {
  /**
   * List bookings with optional filters.
   * GET /bookings
   */
  list(params?: BookingListParams): PaginatedPromise<Booking> {
    const initialPromise = this.transport
      .request<PaginatedResponse<Booking>>('GET', '/bookings', {
        query: params as Record<string, string | number | boolean | undefined>,
      })
      .then((r) => r.data);

    const fetchPage = (cursor: string) =>
      this.transport
        .request<PaginatedResponse<Booking>>('GET', '/bookings', {
          query: { ...params, cursor } as Record<string, string | number | boolean | undefined>,
        })
        .then((r) => r.data);

    return Paginated.from(initialPromise, fetchPage);
  }

  /**
   * Get a single booking by ID.
   * GET /bookings/:id
   */
  async get(id: string): Promise<Booking> {
    const response = await this.transport.request<Booking>(
      'GET',
      `/bookings/${id}`,
    );
    return response.data;
  }

  /**
   * Create a new booking.
   * POST /bookings
   */
  async create(input: CreateBookingInput): Promise<Booking> {
    const response = await this.transport.request<Booking>(
      'POST',
      '/bookings',
      { body: input },
    );
    return response.data;
  }

  /**
   * Update booking metadata.
   * PATCH /bookings/:id
   */
  async update(id: string, input: UpdateBookingInput): Promise<Booking> {
    const response = await this.transport.request<Booking>(
      'PATCH',
      `/bookings/${id}`,
      { body: input },
    );
    return response.data;
  }

  /**
   * Cancel a booking.
   * POST /bookings/:id/cancel
   */
  async cancel(id: string, input?: CancelBookingInput): Promise<Booking> {
    const response = await this.transport.request<Booking>(
      'POST',
      `/bookings/${id}/cancel`,
      { body: input },
    );
    return response.data;
  }

  /**
   * Extend a booking's return date.
   * POST /bookings/:id/extend
   */
  async extend(id: string, input: ExtendBookingInput): Promise<Booking> {
    const response = await this.transport.request<Booking>(
      'POST',
      `/bookings/${id}/extend`,
      { body: input },
    );
    return response.data;
  }

  /**
   * Swap a line item for a different fleet item.
   * POST /bookings/:id/swap-item
   */
  async swapItem(id: string, input: SwapItemInput): Promise<Booking> {
    const response = await this.transport.request<Booking>(
      'POST',
      `/bookings/${id}/swap-item`,
      { body: input },
    );
    return response.data;
  }
}
